def calculate_risk(OLGA_stage):
    """
    Calculate the risk of gastric cancer based on the OLGA stage.

    Parameters:
    OLGA_stage (int): The OLGA stage of gastritis, ranging from 0 to IV.

    Returns:
    float: The risk of gastric cancer.
    """
    if OLGA_stage == 0:
        return 0.03
    elif OLGA_stage == 1:
        return 0.34
    elif OLGA_stage == 2:
        return 1.48
    elif OLGA_stage == 3:
        return 19.1
    elif OLGA_stage == 4:
        return 41.2
    else:
        return "Invalid OLGA stage"
```

